import{_ as r,o as t,c as a,a2 as s}from"./chunks/framework.BWuWLRhz.js";const v=JSON.parse('{"title":"Servers","description":"","frontmatter":{},"headers":[],"relativePath":"server/servers.md","filePath":"server/servers.md"}'),n={name:"server/servers.md"};function i(o,e,l,d,h,p){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="servers" tabindex="-1">Servers <a class="header-anchor" href="#servers" aria-label="Permalink to &quot;Servers&quot;">‚Äã</a></h1><p>A <strong>Server</strong> is a registered machine that Tragwerk deploys to. You add the connection details and credentials once; Tragwerk then provisions the machine and runs your applications on it.</p><h2 id="register-a-server" tabindex="-1">Register a server <a class="header-anchor" href="#register-a-server" aria-label="Permalink to &quot;Register a server&quot;">‚Äã</a></h2><p>In the UI, create a new server and provide:</p><ul><li>A <strong>name</strong> to identify the server.</li><li><strong>Connection details</strong> ‚Äî the host (IP or hostname) and SSH port.</li><li>A <strong>credential</strong> ‚Äî the SSH key or password used to authenticate.</li></ul><p>Manage reusable SSH keys and passwords under <a href="/app/registries-credentials">Registries &amp; Credentials</a>, then select one when registering the server.</p><p>Once registered, run <a href="/server/server-setup">Server Setup</a> to provision the Docker environment before deploying.</p><h2 id="how-credentials-are-used" tabindex="-1">How credentials are used <a class="header-anchor" href="#how-credentials-are-used" aria-label="Permalink to &quot;How credentials are used&quot;">‚Äã</a></h2><p>Credentials authenticate Tragwerk&#39;s SSH connection to the server. They are used for:</p><ul><li>The automated <a href="/server/server-setup">server setup</a> job.</li><li>Every deploy and management action (build, start/stop containers, blue/green switches, cleanup).</li></ul><p>A separate kind of credential ‚Äî a <strong>registry</strong> ‚Äî lets the server pull private container images during builds and deploys. See <a href="/app/registries-credentials">Registries &amp; Credentials</a>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Store SSH keys as credentials rather than passwords where possible, and reuse a single credential across servers that share a key.</p></div><h2 id="edit-and-delete" tabindex="-1">Edit and delete <a class="header-anchor" href="#edit-and-delete" aria-label="Permalink to &quot;Edit and delete&quot;">‚Äã</a></h2><ul><li><strong>Edit</strong> a server to update its host, port, or selected credential ‚Äî for example after rotating an SSH key or moving the server.</li><li><strong>Delete</strong> a server to remove it from Tragwerk. Removing a server detaches it from any projects/environments that targeted it; remove or repoint those deployments first.</li></ul><h2 id="relationship-to-projects-and-environments" tabindex="-1">Relationship to projects and environments <a class="header-anchor" href="#relationship-to-projects-and-environments" aria-label="Permalink to &quot;Relationship to projects and environments&quot;">‚Äã</a></h2><p>A server is the deploy target for your <a href="/app/environments">environments</a>. When an environment deploys, Tragwerk connects to the assigned server over SSH, generates the per-application Docker configuration, and brings up the containers there. Multiple applications and environments can share the same server ‚Äî each is routed by its own hostname through Traefik.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">‚Äã</a></h2><ul><li><a href="/server/server-setup">Server Setup</a></li><li><a href="/app/registries-credentials">Registries &amp; Credentials</a></li><li><a href="/server/architecture-on-host">Architecture on the Host</a></li><li><a href="/app/environments">Environments</a></li></ul>',18)])])}const u=r(n,[["render",i]]);export{v as __pageData,u as default};
